def __init__(self, Tc, Pc, a2, a3, a4, a5):
    self.coeffs = (Tc, Pc, a2, a3, a4, a5)
    super().__init__(func=self._eval)

def _eval(self, T):
    Tc, Pc, a2, a3, a4, a5 = self.coeffs
    Tr = T / Tc
    tau = 1 - Tr
    ln_f = np.log(Pc) + (1 / Tr) * (a2 * tau + a3 * tau**1.5 + a4 * tau**3 + a5 * tau**6)
    return np.exp(ln_f)

