def _eval(self, T):
    a0, a1, a2, a3, a4, a5 = self.coeffs
    ln_K = a0 + a1 / T + a2 * np.log(T) + a3 * T + a4 * T**2 + a5 * T**3
    return np.exp(ln_K)

